/**
 * @summary List all users (admin only)
 */
export const getListAllUsersUrl = () => {
  return `/api/admin/users`;
};

export const listAllUsers = async (
  options?: RequestInit,
): Promise<UserProfile[]> => {
  return customFetch<UserProfile[]>(getListAllUsersUrl(), {
    ...options,
    method: "GET",
  });
};

export const getListAllUsersQueryKey = () => {
  return [`/api/admin/users`] as const;
};

export const getListAllUsersQueryOptions = <
  TData = Awaited<ReturnType<typeof listAllUsers>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof listAllUsers>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListAllUsersQueryKey();

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listAllUsers>>> = ({
    signal,
  }) => listAllUsers({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listAllUsers>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListAllUsersQueryResult = NonNullable<
  Awaited<ReturnType<typeof listAllUsers>>
>;
export type ListAllUsersQueryError = ErrorType<unknown>;

/**
 * @summary List all users (admin only)
 */

export function useListAllUsers<
  TData = Awaited<ReturnType<typeof listAllUsers>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof listAllUsers>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListAllUsersQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Block/unblock user (admin only)
 */
export const getToggleUserBlockUrl = (id: number) => {
  return `/api/admin/users/${id}/block`;
};

export const toggleUserBlock = async (
  id: number,
  toggleBlockBody: ToggleBlockBody,
  options?: RequestInit,
): Promise<UserProfile> => {
  return customFetch<UserProfile>(getToggleUserBlockUrl(id), {
    ...options,
    method: "PUT",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(toggleBlockBody),
  });
};

export const getToggleUserBlockMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof toggleUserBlock>>,
    TError,
    { id: number; data: BodyType<ToggleBlockBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof toggleUserBlock>>,
  TError,
  { id: number; data: BodyType<ToggleBlockBody> },
  TContext
> => {
  const mutationKey = ["toggleUserBlock"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof toggleUserBlock>>,
    { id: number; data: BodyType<ToggleBlockBody> }
  > = (props) => {
    const { id, data } = props ?? {};

    return toggleUserBlock(id, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ToggleUserBlockMutationResult = NonNullable<
  Awaited<ReturnType<typeof toggleUserBlock>>
>;
export type ToggleUserBlockMutationBody = BodyType<ToggleBlockBody>;
export type ToggleUserBlockMutationError = ErrorType<unknown>;

/**
 * @summary Block/unblock user (admin only)
 */
export const useToggleUserBlock = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof toggleUserBlock>>,
    TError,
    { id: number; data: BodyType<ToggleBlockBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof toggleUserBlock>>,
  TError,
  { id: number; data: BodyType<ToggleBlockBody> },
  TContext
> => {
  return useMutation(getToggleUserBlockMutationOptions(options));
};
